INSERT INTO employees (last_name, first_name, paylocity_id, job_title, position, department, hire_date, is_active, employee_number)
SELECT last_name, first_name, paylocity_id, job_title, position, department, hire_date, is_active, paylocity_id FROM source_rows
ON CONFLICT ((lower(last_name)), (lower(first_name))) DO UPDATE SET
  paylocity_id = COALESCE(EXCLUDED.paylocity_id, employees.paylocity_id),
  employee_number = COALESCE(EXCLUDED.employee_number, employees.employee_number),
  job_title = COALESCE(EXCLUDED.job_title, employees.job_title),
  position = COALESCE(EXCLUDED.position, employees.position),
  department = COALESCE(EXCLUDED.department, employees.department),
  hire_date = COALESCE(EXCLUDED.hire_date, employees.hire_date),
  is_active = EXCLUDED.is_active,
  terminated_at = CASE WHEN EXCLUDED.is_active = false AND employees.terminated_at IS NULL THEN now() ELSE employees.terminated_at END,
  updated_at = now();